package com.example.myapplication

import com.example.myapplication.LocalModelTokens.CHANNEL_END
import com.example.myapplication.LocalModelTokens.TURN_END
import com.example.myapplication.LocalModelTokens.TURN_MODEL
import com.example.myapplication.LocalModelTokens.TURN_START
import com.example.myapplication.LocalModelTokens.TURN_USER

// PromptMapper, clean tags
object PromptMapper {

    //change history to Gemma 4 Prompt
    fun mapToGemma4Prompt(history: List<ChatMessage>, newUserInput: String): String {
        val sb = StringBuilder()

        // 1. append history
        history.takeLast(10).forEach { msg ->
            // trim()
            val cleanContent = msg.content.trim()
            if (cleanContent.isNotEmpty()) {
                sb.append(TURN_START).append(msg.role).append("\n")
                sb.append(cleanContent).append(TURN_END)
            }
        }

        // 2. append user input
        sb.append(TURN_USER).append(newUserInput).append(TURN_END)

        // 3. append model turn
        sb.append(TURN_MODEL)

        return sb.toString()
    }

//  handle in LocalModelOutputRawContentHandler.kt
//    fun cleanResponse(text: String): String {
//        return text
//            .replace(CHANNEL_END, "")
//    }
}

package com.example.myapplication

import com.example.myapplication.LocalModelTokens.CHANNEL_END
import com.example.myapplication.LocalModelTokens.THINK_CHANNEL
import com.example.myapplication.LocalModelTokens.THINK_TRIGGER
import com.example.myapplication.LocalModelTokens.TURN_END
import com.example.myapplication.LocalModelTokens.TURN_MODEL
import com.example.myapplication.LocalModelTokens.TURN_START
import com.example.myapplication.LocalModelTokens.TURN_USER

// PromptMapper, clean tags
object PromptMapper {

    /**
     * Build a Gemma 4 prompt from chat history.
     *
     * @param enableThinking  When true:
     *   - Inserts <|think|> immediately after "<|turn>system\n" (before system content)
     *   - Appends <|channel>thought at the end of the model turn prefix to seed thinking
     *
     * Sample when enableThinking = true:
     *   <|turn>system\n<|think|>You are a helpful ai fitness coach.<turn|>\n
     *   <|turn>user\nHello<turn|>\n
     *   <|turn>model\n<|channel>thought
     */
    fun mapToGemma4Prompt(
        history: List<ChatMessage>,
        newUserInput: String,
        enableThinking: Boolean = false
    ): String {
        val sb = StringBuilder()

        // 1. append history
        history.takeLast(10).forEach { msg ->
            val cleanContent = msg.content.trim()
            if (cleanContent.isNotEmpty()) {
                sb.append(TURN_START).append(msg.role).append("\n")
                // inject <|think|> right after "<|turn>system\n" when thinking is enabled
                if (enableThinking && msg.role == "system") {
                    sb.append(THINK_TRIGGER)
                }
                sb.append(cleanContent).append(TURN_END)
            }
        }

        // 2. append user input
        sb.append(TURN_USER).append(newUserInput).append(TURN_END)

        // 3. append model turn prefix; seed thinking channel if enabled
        sb.append(TURN_MODEL)
        if (enableThinking) {
            sb.append(THINK_CHANNEL)  // "<|channel>thought" – model output starts inside thinking
        }

        return sb.toString()
    }
}

package com.example.myapplication

import androidx.room.Dao
import androidx.room.Delete
import androidx.room.Insert
import androidx.room.OnConflictStrategy
import androidx.room.Query
import androidx.room.Transaction
import androidx.room.Update
import java.util.UUID

@Dao
interface UserProfileDao {
    @Insert(onConflict = OnConflictStrategy.IGNORE)
    suspend fun insertUserProfile(userProfile: UserProfile): Long

    @Update
    suspend fun updateUserProfile(userProfile: UserProfile)

    @Delete
    suspend fun deleteUserProfile(userProfile: UserProfile)

    @Query("SELECT * FROM user_profile WHERE user_id = :userId")
    suspend fun getUserProfileByUserId(userId: UUID): UserProfile?

    @Query("SELECT * FROM user_profile WHERE profile_name = :name")
    suspend fun getUserProfileByProfileName(name: String): UserProfile?

    @Query("SELECT * FROM user_profile")
    suspend fun getAllUserProfiles(): List<UserProfile>

    @Query("DELETE FROM user_profile WHERE user_id = :userId")
    suspend fun deleteUserProfileByUserId(userId: UUID)
}

@Dao
interface ChatDao {
    @Insert
    suspend fun insertChat(chat: Chat): Long

    @Update
    suspend fun updateChat(chat: Chat)

    @Delete
    suspend fun deleteChat(chat: Chat)

    @Query("SELECT * FROM chat WHERE chatId = :chatId")
    suspend fun getChatByChatId(chatId: Int): Chat?

    @Query("SELECT * FROM chat WHERE user_id = :userId ORDER BY chat_updated_at_timestamp ASC")
    suspend fun getChatsByUserId(userId: UUID): List<Chat>

    @Query("SELECT * FROM chat WHERE user_id = :userId AND chat_created_at_timestamp > :timestamp ORDER BY chat_updated_at_timestamp ASC")
    suspend fun getChatsByUserIdWithTimestamp(userId: UUID, timestamp: Long): List<Chat>

    @Query("DELETE FROM chat WHERE chatId = :chatId")
    suspend fun deleteChatByChatId(chatId: Int)

    @Query("UPDATE chat SET system_prompt = :prompt, chat_updated_at_timestamp = :timestamp WHERE chatId = :chatId")
    suspend fun updateSystemPrompt(chatId: Int, prompt: String, timestamp: Long)
}

@Dao
interface MessageDao {
    @Insert
    suspend fun insertMessage(message: Message)

    //=============
    @Insert
    suspend fun insertMessages(messages: List<Message>)

    @Insert
    suspend fun insertMessages(vararg messages: Message)
    //=============

    @Update
    suspend fun updateMessage(message: Message)

    @Delete
    suspend fun deleteMessage(message: Message)

    @Query("SELECT * FROM message WHERE messageId = :messageId")
    suspend fun getMessageByMessageId(messageId: UUID): Message?

    @Query("SELECT * FROM message WHERE chat_id = :chatId ORDER BY message_created_at_timestamp ASC")
    suspend fun getMessagesByChatId(chatId: Int): List<Message>

    @Query("SELECT * FROM message WHERE user_id = :userId ORDER BY message_created_at_timestamp ASC")
    suspend fun getMessagesByUserId(userId: UUID): List<Message>

    @Query("SELECT * FROM message WHERE chat_id = :chatId AND is_user_message = :isUser ORDER BY message_created_at_timestamp DESC LIMIT 1")
    suspend fun getLastUserMessageByChatId(chatId: Int, isUser: Boolean): Message?

    @Query("SELECT * FROM message WHERE chat_id = :chatId AND message_created_at_timestamp > :timestamp ORDER BY message_created_at_timestamp ASC")
    suspend fun getRecentMessagesChatId(chatId: Int, timestamp: Long): List<Message>

    @Query("DELETE FROM message WHERE chat_id = :chatId")
    suspend fun deleteMessagesByChatId(chatId: Int)

    @Query("DELETE FROM message WHERE messageId = :messageId")
    suspend fun deleteMessageByMessageId(messageId: UUID)

    @Query("SELECT * FROM message WHERE chat_id = :chatId ORDER BY message_created_at_timestamp ASC LIMIT :limit")
    suspend fun getLimitedMessagesByChatId(chatId: Int, limit: Int = 50): List<Message>
}





























